                      select
                          *,
                          row_number() over (partition by reforderid order by ifnull(RealGet, 0) desc) as rn
                      from dwd.dwd_finance_sr_getmoneylog_view
                  ) b
                                     on a.order_serial_id = b.reforderid and b.rn = 1
                           left join dim.dim_srsv_paychannel_view c
                                     on a.pay_chanel_id = c.id
                           left join dim.dim_sr_recharge_sdk_exclude d
                                     on a.order_id = d.order_number
                  where d.ym is null and a.coo_notify_time >= '2021-06-27'
                    and a.product_id not in('6833','8211','2311')
                    and date(a.coo_notify_time) >= date_format(date_sub('${dt}', interval 1 month), '%Y-%m-01')
                    and date(a.coo_notify_time) <= last_day(date_sub('${dt}', interval 1 month))
              ) a
         union all
         select
             a.dt,
             a.ProductId as product_id,
             a.UserId as user_id,
             a.BookId as book_id,
             Id as order_id,
             '-' as coo_order_id,
             null as shop_item_id,
             2 as report_type,
             a.Amount as amount,
             a.RemainAmount as remain_amount,
             a.RemainAmount as remain_amount_all,
             null as cost,
             CreateTime,
             null as ext3,
             null asduration_time,
             'MOBOREADER' as corp,
             'leave' as asdel_col,
             'leave' as leave_col,
             'leave' as del_col1
         from dwd.dwd_finance_sr_usermoneylog_view a
         where dt >= date_format(date_sub('${dt}', interval 1 month), '%Y-%m-01')
           and dt <= last_day(date_sub('${dt}', interval 1 month))
     ) a where del_col1='leave' and corp ='MOBOREADER'
-- 剔除重复订单id
           and order_id not in(select order_id from ads.ads_sr_finance_book_recharge_consume_info_delete)
;
